sys_ui_page.client_script:
// ============================================================
// SVEM Command Center - Manager Dashboard
// Self-contained: no UX framework dependency
// ============================================================

var API_BASE = '/api/now/table';
var HEADERS = { 'Accept':'application/json','Content-Type':'application/json','X-UserToken': window.g_ck || '' };

function ev(f){ if(!f) return ''; if(typeof f==='object') return f.display_value||f.value||''; return f; }
function eid(f){ if(!f) return ''; if(typeof f==='object') return f.value||''; return f; }
function escHtml(s){ var d=document.createElement('div'); d.appendChild(document.createTextNode(s||'')); return d.innerHTML; }

function apiGet(table, params){
    var url = API_BASE+'/'+table;
    if(params){ var qs=[]; for(var k in params){ qs.push(encodeURIComponent(k)+'='+encodeURIComponent(params[k])); } url+='?'+qs.join('&'); }
    return fetch(url,{method:'GET',headers:HEADERS}).then(function(r){ if(!r.ok) throw new Error('API '+r.status); return r.json(); }).then(function(d){ return d.result||[]; });
}
function apiPatch(table, sysId, data){
    return fetch(API_BASE+'/'+table+'/'+sysId,{method:'PATCH',headers:HEADERS,body:JSON.stringify(data)}).then(function(r){ if(!r.ok) throw new Error('API '+r.status); return r.json(); }).then(function(d){ return d.result; });
}

var allJobs=[], allStaff=[], allMachines=[];
var selectedAssignStaff = null;
var currentTab = 'overview';

function loadAll(){
    return Promise.all([
        apiGet('x_1964226_svem_com_jobs',{sysparm_display_value:'all',sysparm_fields:'sys_id,job_number,po_number,customer,job_status,priority,assigned_to,assigned_machine,customer_due_date,ship_by_date,ship_status,quantity_due,notes,job_type',sysparm_query:'ORDERBYpriority',sysparm_limit:'200'}).then(function(j){allJobs=j;}),
        apiGet('x_1964226_svem_com_staff',{sysparm_display_value:'all',sysparm_fields:'sys_id,name,employee_id,role,shift,status,current_job,current_machine,jobs_completed_this_week,notes',sysparm_limit:'200'}).then(function(s){allStaff=s;}),
        apiGet('x_1964226_svem_com_machines',{sysparm_display_value:'all',sysparm_fields:'sys_id,machine_name,machine_number,machine_type,status,current_job,uptime_percentage',sysparm_limit:'50'}).then(function(m){allMachines=m;})
    ]);
}

function refreshAll(){
    return loadAll().then(function(){ renderCurrentTab(); });
}

function renderCurrentTab(){
    if(currentTab==='overview') renderOverview();
    else if(currentTab==='jobs') renderJobs();
    else if(currentTab==='staff') renderStaff();
    else if(currentTab==='machines') renderMachines();
    else if(currentTab==='assign') renderAssign();
    else if(currentTab==='review') renderReview();
}

// ---- TAB SWITCHING ----
function switchTab(name, btn){
    currentTab = name;
    var tabs = document.querySelectorAll('.tab-content');
    for(var i=0;i<tabs.length;i++) tabs[i].className='tab-content';
    document.getElementById('tab-'+name).className='tab-content active';
    var btns = document.querySelectorAll('.nav-btn');
    for(var j=0;j<btns.length;j++) btns[j].className=btns[j].className.replace(' active','');
    if(btn) btn.className+=' active';
    renderCurrentTab();
}

// ---- HELPERS ----
function countByStatus(status){
    var c=0; for(var i=0;i<allJobs.length;i++){ if(eid(allJobs[i].job_status)===status) c++; } return c;
}
function countByPriority(pri){
    var c=0; for(var i=0;i<allJobs.length;i++){ if(eid(allJobs[i].priority)===pri) c++; } return c;
}
function staffJobCount(staffSysId){
    var c=0; for(var i=0;i<allJobs.length;i++){
        var st=eid(allJobs[i].job_status);
        if(eid(allJobs[i].assigned_to)===staffSysId && st!=='complete' && st!=='shipped') c++;
    } return c;
}
function truncate(s,n){ s=s||''; return s.length>n ? s.substring(0,n)+'...' : s; }
function priorityColor(p){
    if(p==='critical') return '#EF4444';
    if(p==='high') return '#F59E0B';
    if(p==='medium') return '#3B82F6';
    return '#8B8D97';
}
function statusBadge(status){
    return '<span class="badge '+escHtml(status)+'">'+escHtml(status.replace(/_/g,' '))+'</span>';
}
function formatRole(r){ return r ? r.replace(/_/g,' ').replace(/\b\w/g,function(c){return c.toUpperCase();}) : ''; }

// ---- OVERVIEW ----
function renderOverview(){
    var total=allJobs.length;
    var notStarted=countByStatus('not_started');
    var assigned=countByStatus('assigned');
    var inProgress=countByStatus('in_progress');
    var pendingReview=countByStatus('pending_review');
    var complete=countByStatus('complete');
    var shipped=countByStatus('shipped');

    var critical=countByPriority('critical');
    var high=countByPriority('high');

    var activeStaff=0;
    for(var i=0;i<allStaff.length;i++){
        var ss=eid(allStaff[i].status);
        if(ss==='available'||ss==='assigned') activeStaff++;
    }
    var runningMachines=0;
    for(var j=0;j<allMachines.length;j++){
        if(eid(allMachines[j].status)==='running') runningMachines++;
    }

    var html='';
    // KPI row
    html+='<div class="kpi-grid">';
    html+='<div class="kpi-card"><div class="kpi-num">'+total+'</div><div class="kpi-label">Total Jobs</div></div>';
    html+='<div class="kpi-card"><div class="kpi-num accent">'+inProgress+'</div><div class="kpi-label">In Progress</div></div>';
    html+='<div class="kpi-card"><div class="kpi-num warning">'+(pendingReview)+'</div><div class="kpi-label">Pending Review</div></div>';
    html+='<div class="kpi-card"><div class="kpi-num success">'+complete+'</div><div class="kpi-label">Complete</div></div>';
    html+='</div>';

    // Secondary KPIs
    html+='<div class="kpi-grid four">';
    html+='<div class="kpi-card-sm"><div class="kpi-num-sm">'+notStarted+'</div><div class="kpi-label">Not Started</div></div>';
    html+='<div class="kpi-card-sm"><div class="kpi-num-sm" style="color:#A78BFA">'+assigned+'</div><div class="kpi-label">Assigned</div></div>';
    html+='<div class="kpi-card-sm"><div class="kpi-num-sm">'+shipped+'</div><div class="kpi-label">Shipped</div></div>';
    html+='<div class="kpi-card-sm"><div class="kpi-num-sm" style="color:#EF4444">'+critical+'</div><div class="kpi-label">Critical</div></div>';
    html+='</div>';

    // Resources
    html+='<div class="section-header">Resources</div>';
    html+='<div class="kpi-grid two">';
    html+='<div class="kpi-card"><div class="kpi-num accent">'+activeStaff+' <span style="font-size:14px;color:#8B8D97">/ '+allStaff.length+'</span></div><div class="kpi-label">Staff Active</div></div>';
    html+='<div class="kpi-card"><div class="kpi-num success">'+runningMachines+' <span style="font-size:14px;color:#8B8D97">/ '+allMachines.length+'</span></div><div class="kpi-label">Machines Running</div></div>';
    html+='</div>';

    // Urgent jobs
    var urgent=[];
    for(var u=0;u<allJobs.length;u++){
        var p=eid(allJobs[u].priority);
        var st=eid(allJobs[u].job_status);
        if((p==='critical'||p==='high') && st!=='complete' && st!=='shipped') urgent.push(allJobs[u]);
    }
    if(urgent.length>0){
        html+='<div class="section-header">Urgent Jobs ('+urgent.length+')</div>';
        for(var k=0;k<urgent.length&&k<8;k++){
            html+=renderJobRow(urgent[k]);
        }
    }

    document.getElementById('tab-overview').innerHTML=html;
}

// ---- JOBS ----
function renderJobs(){
    var html='<div class="section-header">All Jobs ('+allJobs.length+')</div>';
    var groups = ['not_started','assigned','in_progress','pending_review','complete','shipped'];
    var labels = {'not_started':'Not Started','assigned':'Assigned','in_progress':'In Progress','pending_review':'Pending Review','complete':'Complete','shipped':'Shipped'};
    for(var g=0;g<groups.length;g++){
        var status=groups[g];
        var items=[];
        for(var i=0;i<allJobs.length;i++){
            if(eid(allJobs[i].job_status)===status) items.push(allJobs[i]);
        }
        if(items.length===0) continue;
        html+='<div class="stage-label '+status+'">'+labels[status]+' ('+items.length+')</div>';
        for(var j=0;j<items.length;j++){
            html+=renderJobRow(items[j]);
        }
    }
    document.getElementById('tab-jobs').innerHTML=html;
}

function renderJobRow(job){
    var pri=eid(job.priority);
    var st=eid(job.job_status);
    var notes=ev(job.notes);
    var cust=ev(job.customer);
    var assigned=ev(job.assigned_to);
    var h='<div class="job-row" onclick="openJobDetail(\''+eid(job.sys_id)+'\')">';
    h+='<div class="job-row-pri" style="background:'+priorityColor(pri)+'"></div>';
    h+='<div class="job-row-info">';
    h+='<div class="job-row-top"><span class="job-row-num">'+escHtml(ev(job.job_number))+'</span> '+statusBadge(st)+'</div>';
    if(notes) h+='<div class="job-row-notes">'+escHtml(truncate(notes,80))+'</div>';
    h+='<div class="job-row-meta">';
    if(cust) h+='<span>'+escHtml(cust)+'</span>';
    h+='<span>PO: '+escHtml(ev(job.po_number))+'</span>';
    h+='<span>Qty: '+escHtml(ev(job.quantity_due))+'</span>';
    if(assigned) h+='<span>&#9679; '+escHtml(assigned)+'</span>';
    h+='</div>';
    h+='</div></div>';
    return h;
}

function openJobDetail(sysId){
    window.open('/x_1964226_svem_com_jobs.do?sys_id='+sysId,'_blank');
}

// ---- STAFF ----
function renderStaff(){
    var html='<div class="section-header">Staff ('+allStaff.length+')</div>';
    for(var i=0;i<allStaff.length;i++){
        var s=allStaff[i];
        var name=ev(s.name);
        var status=eid(s.status);
        var role=eid(s.role);
        var jc=staffJobCount(eid(s.sys_id));
        html+='<div class="staff-row">';
        html+='<div class="staff-avatar" style="background:'+(['#3B82F6','#22C55E','#F59E0B','#EF4444','#A78BFA','#EC4899'][i%6])+'">'+escHtml((name||'?').charAt(0).toUpperCase())+'</div>';
        html+='<div class="staff-info">';
        html+='<div class="staff-name">'+escHtml(name)+' <span class="staff-empid">'+escHtml(ev(s.employee_id))+'</span></div>';
        html+='<div class="staff-meta">'+escHtml(formatRole(role))+' &middot; '+escHtml(ev(s.shift))+' shift &middot; '+statusBadge(status)+' &middot; '+jc+' active job'+(jc!==1?'s':'')+'</div>';
        html+='</div></div>';
    }
    document.getElementById('tab-staff').innerHTML=html;
}

// ---- MACHINES ----
function renderMachines(){
    var html='<div class="section-header">Machines ('+allMachines.length+')</div>';
    html+='<div class="machine-grid">';
    for(var i=0;i<allMachines.length;i++){
        var m=allMachines[i];
        var st=eid(m.status);
        var curJob=ev(m.current_job);
        html+='<div class="machine-card '+st+'" onclick="openMachineModal(\''+eid(m.sys_id)+'\')">';
        html+='<div class="machine-card-name">'+escHtml(ev(m.machine_name))+'</div>';
        html+='<div class="machine-card-number">'+escHtml(ev(m.machine_number))+'</div>';
        html+=statusBadge(st);
        if(curJob) html+='<div class="machine-card-job">'+escHtml(curJob)+'</div>';
        var up=ev(m.uptime_percentage);
        if(up) html+='<div class="machine-card-up">'+escHtml(up)+'% uptime</div>';
        html+='</div>';
    }
    html+='</div>';
    document.getElementById('tab-machines').innerHTML=html;
}

var selectedMachineSysId=null, selectedMachineStatus=null;
function openMachineModal(sysId){
    selectedMachineSysId=sysId; selectedMachineStatus=null;
    var m=null;
    for(var i=0;i<allMachines.length;i++){ if(eid(allMachines[i].sys_id)===sysId){ m=allMachines[i]; break; } }
    if(!m) return;
    document.getElementById('machineModalName').innerHTML=escHtml(ev(m.machine_name));
    document.getElementById('machineModalInfo').innerHTML=escHtml(ev(m.machine_number))+' &middot; '+escHtml(ev(m.machine_type));
    var opts=document.querySelectorAll('.status-option');
    for(var j=0;j<opts.length;j++) opts[j].className='status-option';
    document.getElementById('machineModal').className='modal-overlay active';
}
function selectMachineStatus(st,el){
    selectedMachineStatus=st;
    var opts=document.querySelectorAll('.status-option');
    for(var i=0;i<opts.length;i++) opts[i].className='status-option';
    el.className='status-option selected';
}
function saveMachineStatus(){
    if(!selectedMachineSysId||!selectedMachineStatus) return;
    apiPatch('x_1964226_svem_com_machines',selectedMachineSysId,{status:selectedMachineStatus}).then(function(){
        closeModal('machineModal'); showToast('Machine updated','success'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

// ---- ASSIGN ----
function renderAssign(){
    var html='<div class="section-header">Assign Work</div>';
    // Staff picker
    html+='<div class="staff-picker">';
    for(var i=0;i<allStaff.length;i++){
        var s=allStaff[i];
        var sid=eid(s.sys_id);
        var name=ev(s.name);
        var sel=selectedAssignStaff===sid?' selected':'';
        var jc=staffJobCount(sid);
        html+='<div class="staff-chip'+sel+'" onclick="selectAssignStaff(\''+sid+'\')">';
        html+='<div class="chip-avatar">'+escHtml((name||'?').charAt(0).toUpperCase())+'</div>';
        html+='<div><div class="chip-name">'+escHtml(name)+'</div><div class="chip-meta">'+jc+' job'+(jc!==1?'s':'')+'</div></div>';
        html+='</div>';
    }
    html+='</div>';

    if(selectedAssignStaff){
        // Two columns: their jobs | available jobs
        html+='<div class="assign-split">';

        // Left: assigned to this person
        html+='<div class="assign-col">';
        html+='<div class="assign-col-header">Their Jobs</div>';
        var theirJobs=[];
        for(var j=0;j<allJobs.length;j++){
            var jst=eid(allJobs[j].job_status);
            if(eid(allJobs[j].assigned_to)===selectedAssignStaff && jst!=='complete' && jst!=='shipped') theirJobs.push(allJobs[j]);
        }
        if(theirJobs.length===0) html+='<div class="empty-state">No active jobs</div>';
        for(var t=0;t<theirJobs.length;t++){
            var tj=theirJobs[t];
            html+='<div class="assign-item">';
            html+='<div class="assign-item-info"><div class="assign-item-num">'+escHtml(ev(tj.job_number))+'</div>';
            var tn=ev(tj.notes); if(tn) html+='<div class="assign-item-notes">'+escHtml(truncate(tn,50))+'</div>';
            html+='</div>';
            html+='<button class="btn-unassign" onclick="unassignJob(\''+eid(tj.sys_id)+'\')">Unassign</button>';
            html+='</div>';
        }
        html+='</div>';

        // Right: available
        html+='<div class="assign-col">';
        html+='<div class="assign-col-header">Available Jobs</div>';
        var avail=[];
        for(var a=0;a<allJobs.length;a++){
            var ast=eid(allJobs[a].job_status);
            var aat=eid(allJobs[a].assigned_to);
            if(!aat && ast!=='complete' && ast!=='shipped') avail.push(allJobs[a]);
        }
        if(avail.length===0) html+='<div class="empty-state">No unassigned jobs</div>';
        for(var v=0;v<avail.length;v++){
            var av=avail[v];
            html+='<div class="assign-item">';
            html+='<div class="assign-item-info"><div class="assign-item-num">'+escHtml(ev(av.job_number))+'</div>';
            var an=ev(av.notes); if(an) html+='<div class="assign-item-notes">'+escHtml(truncate(an,50))+'</div>';
            html+='</div>';
            html+='<button class="btn-assign" onclick="assignJob(\''+eid(av.sys_id)+'\')">Assign</button>';
            html+='</div>';
        }

        // Other staff's jobs
        var others=[];
        for(var o=0;o<allJobs.length;o++){
            var ost=eid(allJobs[o].job_status);
            var oat=eid(allJobs[o].assigned_to);
            if(oat && oat!==selectedAssignStaff && ost!=='complete' && ost!=='shipped') others.push(allJobs[o]);
        }
        if(others.length>0){
            html+='<div class="assign-col-header" style="margin-top:12px;">Other Staff\'s Jobs</div>';
            for(var x=0;x<others.length;x++){
                var oj=others[x];
                html+='<div class="assign-item">';
                html+='<div class="assign-item-info"><div class="assign-item-num">'+escHtml(ev(oj.job_number))+'</div>';
                html+='<div class="assign-item-notes">'+escHtml(ev(oj.assigned_to))+'</div>';
                html+='</div>';
                html+='<button class="btn-reassign" onclick="reassignJob(\''+eid(oj.sys_id)+'\')">Reassign</button>';
                html+='</div>';
            }
        }
        html+='</div>';
        html+='</div>';
    } else {
        html+='<div class="empty-state">Select a staff member above to manage assignments</div>';
    }

    document.getElementById('tab-assign').innerHTML=html;
}

function selectAssignStaff(sysId){
    selectedAssignStaff=sysId;
    renderAssign();
}

function assignJob(jobSysId){
    if(!selectedAssignStaff) return;
    var job=findJob(jobSysId);
    var jobNum=job?ev(job.job_number):'';
    apiPatch('x_1964226_svem_com_jobs',jobSysId,{assigned_to:selectedAssignStaff,job_status:'assigned'}).then(function(){
        showToast(jobNum+' assigned','success'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

function unassignJob(jobSysId){
    var job=findJob(jobSysId);
    var jobNum=job?ev(job.job_number):'';
    if(!confirm('Unassign '+jobNum+'?')) return;
    apiPatch('x_1964226_svem_com_jobs',jobSysId,{assigned_to:'',job_status:'not_started'}).then(function(){
        showToast(jobNum+' unassigned','success'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

function reassignJob(jobSysId){
    if(!selectedAssignStaff) return;
    var job=findJob(jobSysId);
    var jobNum=job?ev(job.job_number):'';
    var staffName='';
    for(var i=0;i<allStaff.length;i++){
        if(eid(allStaff[i].sys_id)===selectedAssignStaff){ staffName=ev(allStaff[i].name); break; }
    }
    if(!confirm('Reassign '+jobNum+' to '+staffName+'?')) return;
    apiPatch('x_1964226_svem_com_jobs',jobSysId,{assigned_to:selectedAssignStaff,job_status:'assigned'}).then(function(){
        showToast(jobNum+' reassigned to '+staffName,'success'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

// ---- REVIEW ----
function renderReview(){
    var pending=[];
    for(var i=0;i<allJobs.length;i++){
        if(eid(allJobs[i].job_status)==='pending_review') pending.push(allJobs[i]);
    }
    var html='<div class="section-header">Pending Review ('+pending.length+')</div>';
    if(pending.length===0){
        html+='<div class="empty-state">No jobs pending review</div>';
    }
    for(var j=0;j<pending.length;j++){
        var p=pending[j];
        var notes=ev(p.notes);
        html+='<div class="review-card">';
        html+='<div class="review-header">';
        html+='<div><div class="review-job">'+escHtml(ev(p.job_number))+'</div>';
        html+='<div class="review-meta">'+escHtml(ev(p.assigned_to))+' &middot; PO: '+escHtml(ev(p.po_number))+'</div>';
        if(notes) html+='<div class="review-notes">'+escHtml(truncate(notes,100))+'</div>';
        html+='</div></div>';
        html+='<div class="review-actions">';
        html+='<button class="action-btn success" onclick="approveJob(\''+eid(p.sys_id)+'\')">Approve</button>';
        html+='<button class="action-btn danger" onclick="rejectJob(\''+eid(p.sys_id)+'\')">Reject</button>';
        html+='</div></div>';
    }
    document.getElementById('tab-review').innerHTML=html;
}

function approveJob(sysId){
    var job=findJob(sysId);
    var jobNum=job?ev(job.job_number):'';
    apiPatch('x_1964226_svem_com_jobs',sysId,{job_status:'complete'}).then(function(){
        showToast(jobNum+' approved','success'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

function rejectJob(sysId){
    var job=findJob(sysId);
    var jobNum=job?ev(job.job_number):'';
    apiPatch('x_1964226_svem_com_jobs',sysId,{job_status:'in_progress'}).then(function(){
        showToast(jobNum+' sent back','warning'); return refreshAll();
    }).catch(function(e){ showToast('Error: '+e.message,'error'); });
}

// ---- UTILS ----
function findJob(sysId){
    for(var i=0;i<allJobs.length;i++){ if(eid(allJobs[i].sys_id)===sysId) return allJobs[i]; } return null;
}

function closeModal(id){ document.getElementById(id).className='modal-overlay'; }

function showToast(msg,type){
    var t=document.getElementById('toast');
    t.innerHTML=escHtml(msg);
    t.className='toast '+(type||'')+' show';
    setTimeout(function(){ t.className='toast'; },2500);
}

// ---- INIT ----
window.onload = function(){
    loadAll().then(function(){
        renderOverview();
    }).catch(function(e){
        document.getElementById('tab-overview').innerHTML='<div class="empty-state">Error loading data: '+escHtml(e.message)+'</div>';
    });
};
